class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        lock_files: bool = False,
        monitor_process: EditorMonitorCallback | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.lock_files = lock_files
        self.monitor_process = monitor_process

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _get_lock_filename(self, filename: str) -> str:
        directory, base = os.path.split(filename)
        return os.path.join(directory, f".{base}.lock")

    def _create_lock_file(self, filename: str) -> str:
        from datetime import datetime

        lock_filename = self._get_lock_filename(filename)

        try:
            fd = os.open(lock_filename, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
        except FileExistsError as e:
            raise ClickException(
                _("Could not acquire lock for {filename!r}: {lock_filename!r}"
                  " already exists").format(
                    filename=filename, lock_filename=lock_filename
                )
            ) from e

        try:
            with os.fdopen(fd, "w") as f:
                f.write(f"PID: {os.getpid()}\nTime: {datetime.now().isoformat()}\n")
        except BaseException:
            with contextlib.suppress(OSError):
                os.unlink(lock_filename)
            raise

        return lock_filename

    def _remove_lock_file(self, lock_filename: str) -> None:
        with contextlib.suppress(OSError):
            os.unlink(lock_filename)

    @contextlib.contextmanager
    def _lock_file_context(self, filename: str) -> cabc.Iterator[None]:
        if not self.lock_files:
            yield
            return

        lock_filename = self._create_lock_file(filename)

        try:
            yield
        finally:
            self._remove_lock_file(lock_filename)

    def _get_process_state(self, pid: int) -> str | None:
        """Return the single-character state code of a process on Linux,
        or ``None`` if it can't be determined (e.g. on other platforms).
        """
        if sys.platform != "linux":
            return None

        try:
            with open(f"/proc/{pid}/stat") as f:
                data = f.read()
        except OSError:
            return None

        # The process name is surrounded by parens and may itself contain
        # parens or spaces, so find the state field after the last ")".
        idx = data.rfind(")")
        if idx == -1:
            return None

        fields = data[idx + 2 :].split()
        return fields[0] if fields else None

    def _monitor_process(
        self,
        process: subprocess.Popen,
        editor_command: str,
        callback: EditorMonitorCallback,
    ) -> None:
        import warnings

        def invoke(event_type: str) -> None:
            try:
                callback(event_type, process.pid, editor_command, time.time())
            except Exception as e:
                warnings.warn(
                    f"Exception raised in monitor_process callback for event"
                    f" {event_type!r}: {e}",
                    UserWarning,
                    stacklevel=2,
                )

        invoke("start")
        suspended = False

        while process.poll() is None:
            state = self._get_process_state(process.pid)

            if state == "T" and not suspended:
                suspended = True
                invoke("suspend")
            elif state not in ("T", None) and suspended:
                suspended = False
                invoke("resume")

            time.sleep(0.1)

        invoke("terminate")

    def edit_file(self, filename: str) -> None:
        import subprocess
        import threading

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        with self._lock_file_context(filename):
            try:
                c = subprocess.Popen(
                    f'{editor} "{filename}"', env=environ, shell=True
                )

                monitor_thread: threading.Thread | None = None

                if self.monitor_process is not None:
                    monitor_thread = threading.Thread(
                        target=self._monitor_process,
                        args=(c, editor, self.monitor_process),
                        daemon=True,
                    )
                    monitor_thread.start()

                exit_code = c.wait()

                if monitor_thread is not None:
                    monitor_thread.join(timeout=1)

                if exit_code != 0:
                    raise ClickException(
                        _("{editor}: Editing failed").format(editor=editor)
                    )
            except OSError as e:
                raise ClickException(
                    _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
                ) from e"}

